A:

Here is an example using threading. This allows Python to run two (or more) separate threads, each doing different things at the same time. (Technically they're not actually at the same time, but both happening alternately, but that's not important in this case). In one thread, you listen for key presses. And in the other thread, you check for the key state and react appropriately. import threading
from pynput import keyboard

class KeyCheckThread(threading.Thread):
 def __init__(self):
 super(KeyCheckThread, self).__init__()
 self.doThing = 0

 def on_press(self, key):
 self.doThing = 1

 def on_release(self, key):
 self.doThing = 0

 def run(self):
 with keyboard.Listener(on_press=self.on_press, on_release=self.on_release) as listener:
 listener.join()

listenerThread = KeyCheckThread()
listenerThread.start()

while(True):
 if listenerThread.doThing == 1:
 print("doThing")

